 class AdminBeautify_Action extends Typecho_Widget implements Widget_Interface_Do{private $c;private $d;private $f;public function __construct($g,$h,$j=NULL){parent::__construct($g,$h,$j);$k->db=Typecho_Db::get();$k->options=Typecho_Widget::widget('Widget_Options');$k->pluginOptions=$k->options->plugin('AdminBeautify');}public function execute(){}private function checkAuth(){$l=Typecho_Widget::widget('Widget_User');if(!$l->hasLogin()){$k->jsonError('未登录',401);}}private function checkAdmin(){$l=Typecho_Widget::widget('Widget_User');if(!$l->hasLogin()||!$l->pass('administrator',true)){$k->jsonError('权限不足',403);}}private function jsonSuccess($n=null,$o='ok'){$k->response->throwJson(array('code'=>0,'message'=>$o,'data'=>$n,));}private function jsonError($o='error',$p=400){$k->response->throwJson(array('code'=>$p,'message'=>$o,'data'=>null,));}public function manifest(){$q=(string) $k->options->title;$s=rtrim((string) $k->options->adminUrl,'/').'/';$t=rtrim((string) $k->options->pluginUrl,'/');$u=$k->pluginOptions->primaryColor?:'purple';$w=array('purple'=>array('theme'=>'#7D5260','bg'=>'#FFFBFE'),'blue'=>array('theme'=>'#556270','bg'=>'#FAFCFF'),'teal'=>array('theme'=>'#4A6363','bg'=>'#F4FBFB'),'green'=>array('theme'=>'#55624C','bg'=>'#F6FBF0'),'orange'=>array('theme'=>'#725A42','bg'=>'#FFFBF6'),'pink'=>array('theme'=>'#74565F','bg'=>'#FFFBFF'),'red'=>array('theme'=>'#775654','bg'=>'#FFFBFF'),);$x=isset($w[$u])?$w[$u]:$w['purple'];$y=$x['theme'];$z=$x['bg'];$aa=isset($k->pluginOptions->pwa_appName)?trim((string) $k->pluginOptions->pwa_appName):'';$bb=isset($k->pluginOptions->pwa_appIcon)?trim((string) $k->pluginOptions->pwa_appIcon):'';$cc=($aa!=='')?$aa:($q.' 管理后台');$dd=($aa!=='')?$aa:($q?:'Admin');$ee=array();if($bb!==''){$ee[]=array('src'=>$bb,'sizes'=>'192x192','type'=>'image/png','purpose'=>'any',);$ee[]=array('src'=>$bb,'sizes'=>'512x512','type'=>'image/png','purpose'=>'any',);$ee[]=array('src'=>$bb,'sizes'=>'512x512','type'=>'image/png','purpose'=>'maskable',);}else{$ff='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 192 192">'.'<rect width="192" height="192" rx="48" fill="'.htmlspecialchars($y).'"/>'.'<text x="96" y="130" font-size="100" text-anchor="middle" fill="#fff" font-family="sans-serif">T</text>'.'</svg>';$gg='data:image/svg+xml;base64,'.base64_encode($ff);$ee[]=array('src'=>$gg,'sizes'=>'any','type'=>'image/svg+xml','purpose'=>'any maskable',);}$hh=array('name'=>$cc,'short_name'=>$dd,'description'=>'Typecho 管理后台 - 由 AdminBeautify 增强','start_url'=>$s,'scope'=>$s,'display'=>'standalone','orientation'=>'any','theme_color'=>$y,'background_color'=>$z,'lang'=>'zh-CN','icons'=>$ee,'screenshots'=>array(),'categories'=>array('productivity','utilities'),);$k->response->setContentType('application/manifest+json');$k->response->setHeader('Cache-Control','public, max-age=3600');echo json_encode($hh,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_PRETTY_PRINT);exit;}public function sw(){$d=$k->options;$t=rtrim((string) $d->pluginUrl,'/');$ii=$t.'/AdminBeautify/assets/style.css?v=2.0.2';$jj=$t.'/AdminBeautify/assets/script.js?v=2.0.2';$kk=dirname(__FILE__).'/assets/sw.js';if(!file_exists($kk)){http_response_code(404);exit;}$ll=file_get_contents($kk);$mm=json_encode(array($ii,$jj),JSON_UNESCAPED_SLASHES);$ll=str_replace('var PRECACHE_URLS = [];','var PRECACHE_URLS = '.$mm.';',$ll);$k->response->setContentType('application/javascript');$k->response->setHeader('Cache-Control','no-cache, no-store, must-revalidate');$k->response->setHeader('Service-Worker-Allowed',rtrim((string) $d->adminUrl,'/').'/');echo $ll;exit;}public function info(){$k->checkAuth();$nn=$k->db->fetchObject($k->db->select(array('COUNT(*)'=>'num'))->from('table.contents')->where('type = ?','post')->where('status = ?','publish'))->num;$oo=$k->db->fetchObject($k->db->select(array('COUNT(*)'=>'num'))->from('table.comments')->where('status = ?','approved'))->num;$pp=$k->db->fetchObject($k->db->select(array('COUNT(*)'=>'num'))->from('table.metas')->where('type = ?','category'))->num;$k->jsonSuccess(array('version'=>'1.4.5','posts'=>(int) $nn,'comments'=>(int) $oo,'categories'=>(int) $pp,));}public function saveSettings(){$k->checkAdmin();$qq=$k->request->from('primaryColor','darkMode','borderRadius','enableAnimation','navPosition');$qq=array_filter($qq,function($rr){return $rr!==null&&$rr!=='';});if(empty($qq)){$k->jsonError('没有需要保存的设置');}try{$ss='AdminBeautify';$tt=$k->options->plugin($ss);$uu=array();foreach($tt as $vv=>$ww){$uu[$vv]=$ww;}foreach($qq as $vv=>$ww){$uu[$vv]=$ww;}$k->db->query($k->db->update('table.options')->rows(array('value'=>serialize($uu)))->where('name = ?','plugin:'.$ss));$k->jsonSuccess($uu,'设置已保存');}catch(Exception $xx){$k->jsonError('保存失败: '.$xx->getMessage(),500);}}public function getSettings(){$k->checkAdmin();$qq=array();foreach($k->pluginOptions as $vv=>$ww){$qq[$vv]=$ww;}$k->jsonSuccess($qq);}public function ping(){$k->jsonSuccess(array('time'=>time(),'plugin'=>'AdminBeautify',),'pong');}public function checkUpdate(){$k->checkAdmin();require_once dirname(__FILE__).'/Updater.php';$yy=new AdminBeautify_Updater();$zz=$yy->fetchLatestRelease();if($zz===false){$k->jsonError('无法连接 GitHub，请检查服务器网络',502);}$aaa=AdminBeautify_Updater::CURRENT_VERSION;$bbb=$zz['version'];$ccc=AdminBeautify_Updater::compareVersion($bbb,$aaa)>0;$ddd=$ccc&&AdminBeautify_Updater::canDirectUpdate($aaa,$bbb);$k->jsonSuccess(array('has_update'=>$ccc,'current'=>$aaa,'latest'=>$bbb,'can_direct'=>$ddd,'html_url'=>$zz['html_url'],'download_url'=>$zz['download_url'],'body'=>$zz['body'],),$ccc?'发现新版本 v'.$bbb:'已是最新版本 v'.$aaa);}public function doUpdate(){$k->checkAdmin();require_once dirname(__FILE__).'/Updater.php';$eee=trim($k->request->get('download_url',''));$fff=trim($k->request->get('new_version',''));if($eee===''){$k->jsonError('缺少 download_url 参数');}if($fff===''){$k->jsonError('缺少 new_version 参数');}$aaa=AdminBeautify_Updater::CURRENT_VERSION;if(!AdminBeautify_Updater::canDirectUpdate($aaa,$fff)){$k->jsonError('版本跨度过大（当前 v'.$aaa.' → v'.$fff.'），请前往 GitHub 手动更新',400);}if(strpos($eee,'github.com')===false&&strpos($eee,'codeload.github.com')===false){$k->jsonError('下载地址不合法',400);}$yy=new AdminBeautify_Updater();$ggg=$yy->doUpdate($eee,$fff);if($ggg['ok']){$k->jsonSuccess(array('details'=>$ggg['details'],'new_version'=>$fff,),$ggg['msg']);}else{$k->jsonError($ggg['msg']."\n详情：".implode("\n",$ggg['details']),500);}}public function syncCompat(){$k->checkAdmin();$hhh=dirname(__FILE__).'/assets/compat/';if(!is_dir($hhh)){$k->jsonError('本地 assets/compat/ 目录不存在',500);}if(!is_writable($hhh)){$k->jsonError('本地 assets/compat/ 目录不可写，请检查文件权限',500);}$iii='https://api.github.com/repos/lhl77/Typecho-Plugin-AdminBeautify/contents/assets/compat';$jjj=$k->httpGet($iii);if($jjj===false){$k->jsonError('无法连接 GitHub API，请检查服务器网络',502);}$kkk=@json_decode($jjj,true);if(!is_array($kkk)){$k->jsonError('GitHub API 返回数据解析失败',502);}$lll=array();foreach($kkk as $mmm){if(!isset($mmm['name'])||!isset($mmm['type']))continue;if($mmm['type']!=='file')continue;if(substr($mmm['name'],-3)!=='.js')continue;$nnn=$mmm['name'];$eee=isset($mmm['download_url'])?$mmm['download_url']:'';if($eee==='')continue;$ooo=$k->httpGet($eee);if($ooo===false){$lll[]=array('file'=>$nnn,'status'=>'error','msg'=>'下载失败');continue;}$ppp=$k->parseVersionFromContent($ooo);$qqq=$hhh.$nnn;if(!file_exists($qqq)){if(file_put_contents($qqq,$ooo)!==false){$lll[]=array('file'=>$nnn,'status'=>'added','version'=>$ppp,'msg'=>'新增');}else{$lll[]=array('file'=>$nnn,'status'=>'error','msg'=>'写入失败');}}else{$rrr=@file_get_contents($qqq,false,null,0,2048);$sss=$rrr!==false?$k->parseVersionFromContent($rrr):'0';if($k->compareVersion($ppp,$sss)>0){if(file_put_contents($qqq,$ooo)!==false){$lll[]=array('file'=>$nnn,'status'=>'updated','version'=>$ppp,'localVersion'=>$sss,'msg'=>'已更新 v'.$sss.' → v'.$ppp,);}else{$lll[]=array('file'=>$nnn,'status'=>'error','msg'=>'写入失败');}}else{$lll[]=array('file'=>$nnn,'status'=>'skip','version'=>$sss,'msg'=>'已是最新 v'.$sss,);}}}$ttt=count(array_filter($lll,function($uuu){return $uuu['status']==='added';}));$vvv=count(array_filter($lll,function($uuu){return $uuu['status']==='updated';}));$www=count(array_filter($lll,function($uuu){return $uuu['status']==='skip';}));$xxx=count(array_filter($lll,function($uuu){return $uuu['status']==='error';}));$k->jsonSuccess(array('results'=>$lll,'summary'=>array('added'=>$ttt,'updated'=>$vvv,'skipped'=>$www,'errors'=>$xxx,'total'=>count($lll),),),'同步完成：新增 '.$ttt.' 个，更新 '.$vvv.' 个，跳过 '.$www.' 个'.($xxx>0?'，失败 '.$xxx.' 个':''));}private function httpGet($yyy){$zzz=array('http'=>array('method'=>'GET','timeout'=>15,'header'=>"User-Agent: AdminBeautify-Typecho-Plugin/2.1.0\r\n"."Accept: application/vnd.github.v3+json\r\n",),'ssl'=>array('verify_peer'=>false,'verify_peer_name'=>false,),);$aaaa=stream_context_create($zzz);$ggg=@file_get_contents($yyy,false,$aaaa);if($ggg!==false)return $ggg;if(!function_exists('curl_init'))return false;$bbbb=curl_init($yyy);curl_setopt_array($bbbb,array(CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>15,CURLOPT_FOLLOWLOCATION=>true,CURLOPT_SSL_VERIFYPEER=>false,CURLOPT_SSL_VERIFYHOST=>false,CURLOPT_USERAGENT=>'AdminBeautify-Typecho-Plugin/2.1.0',CURLOPT_HTTPHEADER=>array('Accept: application/vnd.github.v3+json'),));$ggg=curl_exec($bbbb);$cccc=curl_getinfo($bbbb,CURLINFO_HTTP_CODE);curl_close($bbbb);return($ggg!==false&&$cccc===200)?$ggg:false;}private function parseVersionFromContent($dddd){if(preg_match('/@version\s+([^\s\*\/]+)/i',$dddd,$eeee)){return trim($eeee[1]);}return'0';}private function compareVersion($ffff,$gggg){$hhhh=array_map('intval',explode('.',ltrim((string)$ffff,'vV')));$iiii=array_map('intval',explode('.',ltrim((string)$gggg,'vV')));$jjjj=max(count($hhhh),count($iiii));for($kkkk=0;$kkkk<$jjjj;$kkkk++){$llll=isset($hhhh[$kkkk])?$hhhh[$kkkk]:0;$mmmm=isset($iiii[$kkkk])?$iiii[$kkkk]:0;if($llll>$mmmm)return1;if($llll<$mmmm)return-1;}return0;}public function action(){$nnnn=$k->request->get('do','');if($nnnn==='manifest'){$k->manifest();return;}if($nnnn==='sw'){$k->sw();return;}$k->response->setContentType('application/json');switch($nnnn){case  'ping':$k->ping();break;case  'info':$k->info();break;case  'get-settings':$k->getSettings();break;case  'save-settings':$k->saveSettings();break;case  'sync-compat':$k->syncCompat();break;case  'check-update':$k->checkUpdate();break;case  'do-update':$k->doUpdate();break;default:$k->jsonError('未知的操作: '.$nnnn,404);break;}}}
